// In the Code Node that calculates days
return items.map(item => {
  const firstContact = new Date(item.json.First_Contact_Date);
  firstContact.setHours(0, 0, 0, 0);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const daysSince = Math.floor((today - firstContact) / (1000 * 60 * 60 * 24));

  // CRITICAL: Only send if still active
  const shouldSend = [1, 4, 9, 14, 20, 30].includes(daysSince) && 
                     item.json.Status === 'active' &&
                     item.json.Reply_Received !== 'TRUE';

  return {
    json: {
      ...item.json,
      days_since_first_contact: daysSince,
      should_send: shouldSend
    }
  };
});
